  RouterProvider,
  Outlet,
  Link,
  NavLink,
  useParams,
} from 'react-router-dom';

const posts = [
  { id: 1, title: 'Introdução ao React', excerpt: 'Aprenda os fundamentos...', content: 'React é uma biblioteca JavaScript para construir interfaces de usuário.' },
  { id: 2, title: 'Hooks em profundidade', excerpt: 'useState, useEffect e mais...', content: 'Hooks são funções especiais que permitem usar estado em componentes funcionais.' },
  { id: 3, title: 'React Router na prática', excerpt: 'Navegação como profissional...', content: 'React Router é a biblioteca padrão para roteamento em React.' },
];

function Layout() {
  // Melhore: adicione Header com NavLinks e Footer
  return (
    <div>
      <header className="p-4 border-b">
        <Link to="/">MeuBlog</Link>
      </header>
      <main className="p-6"><Outlet /></main>
    </div>
  );
}

function Home() {
  // Melhore: liste os posts com Links para /post/:id
  return <div><h1>Blog</h1><p>Implemente a lista de posts aqui</p></div>;
}

function PostDetail() {
  // Implemente: useParams + buscar post no array + exibir
  const { id } = useParams();
  return <div><p>Detalhe do post {id} — implemente aqui</p></div>;
}

function About() {
  return <div><h1>Sobre</h1><p>Um mini blog com React Router.</p></div>;
}

function NotFound() {
  return <div><h1>404</h1><p>Página não encontrada.</p></div>;
}

const router = createBrowserRouter([
  {
    element: <Layout />,
    children: [
      { path: '/', element: <Home /> },
      { path: '/post/:id', element: <PostDetail /> },
      { path: '/sobre', element: <About /> },
      { path: '*', element: <NotFound /> },
    ],
  },
]);

export default function App() {
  return <RouterProvider router={router} />;
}

