import {
  createBrowserRouter,
  RouterProvider,
  Outlet,
  Link,
  NavLink,
  useParams,
} from 'react-router-dom';

const posts = [
  { id: 1, title: 'Introdução ao React', excerpt: 'Aprenda os fundamentos...', content: 'React é uma biblioteca JavaScript para construir interfaces de usuário.' },
  { id: 2, title: 'Hooks em profundidade', excerpt: 'useState, useEffect e mais...', content: 'Hooks são funções especiais que permitem usar estado em componentes funcionais.' },
  { id: 3, title: 'React Router na prática', excerpt: 'Navegação como profissional...', content: 'React Router é a biblioteca padrão para roteamento em React.' },
];

const navLinkClass = ({ isActive }) =>
  isActive ? 'text-blue-500 font-bold' : 'text-gray-400 hover:text-gray-200';

function Layout() {
  return (
    <div className="min-h-screen flex flex-col">
      <header className="flex items-center justify-between border-b border-gray-700 p-4">
        <Link to="/" className="text-xl font-bold text-white">MeuBlog</Link>
        <nav className="flex gap-4">
          <NavLink to="/" end className={navLinkClass}>Home</NavLink>
          <NavLink to="/sobre" className={navLinkClass}>Sobre</NavLink>
        </nav>
      </header>
      <main className="flex-1 p-6">
        <Outlet />
      </main>
      <footer className="border-t border-gray-700 p-4 text-center text-sm text-gray-500">
        MeuBlog © 2024
      </footer>
    </div>
  );
}

function Home() {
  return (
    <div>
      <h1 className="text-2xl font-bold mb-4">Posts recentes</h1>
      <div className="space-y-4">
        {posts.map(post => (
          <article key={post.id} className="rounded-lg border border-gray-700 p-4">
            <h2 className="text-lg font-semibold">
              <Link to={`/post/${post.id}`} className="text-blue-400 hover:underline">
                {post.title}
              </Link>
            </h2>
            <p className="mt-1 text-gray-400">{post.excerpt}</p>
          </article>
        ))}
      </div>
    </div>
  );
}

function PostDetail() {
  const { id } = useParams();
  const post = posts.find(p => p.id === Number(id));

  if (!post) {
    return (
      <div>
        <h1 className="text-xl font-bold">Post não encontrado</h1>
        <Link to="/" className="text-blue-400">← Voltar</Link>
      </div>
    );
  }

  return (
    <article>
      <Link to="/" className="text-blue-400 text-sm">← Voltar aos posts</Link>
      <h1 className="text-2xl font-bold mt-2">{post.title}</h1>
      <p className="mt-4 text-gray-300">{post.content}</p>
    </article>
  );
}

function About() {
  return (
    <div>
      <h1 className="text-2xl font-bold">Sobre</h1>
      <p className="mt-2 text-gray-400">Um mini blog construído com React Router.</p>
    </div>
  );
}

function NotFound() {
  return (
    <div className="text-center">
      <h1 className="text-4xl font-bold">404</h1>
      <p className="mt-2 text-gray-400">Página não encontrada.</p>
      <Link to="/" className="mt-4 inline-block text-blue-400">← Voltar à home</Link>
    </div>
  );
}

const router = createBrowserRouter([
  {
    element: <Layout />,
    children: [
      { path: '/', element: <Home /> },
      { path: '/post/:id', element: <PostDetail /> },
      { path: '/sobre', element: <About /> },
      { path: '*', element: <NotFound /> },
    ],
  },
]);

export default function App() {
  return <RouterProvider router={router} />;
}
